import i18n, { Callback, TFunction } from 'i18next';
import { asyncUpdateI18n, getLanguage, getProjectLanguage, i18nInit } from './utils';
import { ASYNC_COMPONENT_LIST, DOMAIN_URL, i18nInitProps } from './const';
// 提取i18n的changeLanguage
const originalChangeLanguage = i18n.changeLanguage;
/**
 * 切换项目翻译数据
 * @param customOption
 * @param source
 * @param callback
 * @param asyncComponentList  // 需要异步请求部件列表
 * @returns
 */
export const sptChangeLanguage = (
    customOption: i18nInitProps,
    source: object = {},
    callback?: Callback,
    asyncComponentList: Set<string> = ASYNC_COMPONENT_LIST
) => {
    const options = {
        ...customOption,
        // 如果自定义参数无法获取到 domainUrl，则使用线上的 i18n api url 作为回退值
        domainUrl: customOption.domainUrl || DOMAIN_URL,
        // 如果自定义参数无法获取到偏好语言，则使用 'zh' 作为回退值
        language: customOption.language || 'zh'
    };
    console.log('异步请求部件:', asyncComponentList);
    if (asyncComponentList?.size) {
        for (const component of customOption.componentList) {
            if (asyncComponentList.has(component)) {
                getLanguage({ ...options, component })
                    .then((res) => {
                        // 添加至i18n Bundle,覆盖模式
                        i18n.addResourceBundle(
                            options.language!,
                            'translation',
                            { ...res },
                            true,
                            true
                        );
                    })
                    .catch((error) => {
                        console.error(error);
                    });
            }
        }
    }

    return new Promise<TFunction>((resolve, reject) => {
        // 拉取当前项目所需翻译数据
        getProjectLanguage({
            ...options, // 过滤异步请求的部件
            componentList: asyncComponentList?.size
                ? customOption.componentList.filter(
                      (component) => !asyncComponentList.has(component)
                  )
                : customOption.componentList
        })
            .then((data) => {
                // 添加至i18n Bundle,覆盖模式
                i18n.addResourceBundle(
                    options.language!,
                    'translation',
                    { ...source, ...data },
                    true,
                    true
                );
                // 拦截changeLanguage，通过接口返回数据灌入实例，再触发change
                resolve(originalChangeLanguage(options?.language!, callback));
            })
            .catch((error) => reject(error));
    });
};

/**
 *
 * @param options i18n 初始化配置
 * @param source 预加载的数据
 * @returns
 */
export const initSpotterI18n = (customOption: i18nInitProps, source: object = {}) => {
    // 需要异步请求的部件
    console.log('异步请求部件:', ASYNC_COMPONENT_LIST);
    const options = {
        ...customOption,
        // 如果自定义参数无法获取到 domainUrl，则使用线上的 i18n api url 作为回退值
        domainUrl: customOption.domainUrl || DOMAIN_URL,
        // 如果自定义参数无法获取到偏好语言，则使用 'zh' 作为回退值
        language: customOption.language || 'zh'
    };

    return new Promise<typeof i18n>((resolve, reject) => {
        const initializeI18n = async () => {
            try {
                // 同步请求部件
                const data = await getProjectLanguage({
                    ...options,
                    // 过滤异步请求的部件
                    componentList: customOption.componentList.filter(
                        (component) => !ASYNC_COMPONENT_LIST.has(component)
                    )
                });
                // 初始化
                await i18nInit(options, { ...source,...data });
                 // 异步请求部件
                 for (const component of customOption.componentList) {
                    if (ASYNC_COMPONENT_LIST.has(component)) {
                        console.log('异步更新:', component);
                        asyncUpdateI18n(options, component);
                    }
                }
                i18n.changeLanguage = (lng: string, callback?: Callback | undefined) =>
                    sptChangeLanguage(
                        { ...options, language: lng },
                        source,
                        callback,
                        ASYNC_COMPONENT_LIST
                    );

                resolve(i18n);
            } catch (initError) {
                console.error('获取资源存在错误', initError);
                // 失败时再次 init 防止子应用加载失败
                try {
                    await i18nInit(options, { ...source });
                    resolve(i18n);
                } catch (i18nInitError) {
                    reject(i18nInitError);
                }
            }
        };
        initializeI18n();
    });
};
